#!/usr/bin/env python3
"""
DataFetcher - Calls the API endpoint defined in config.json
"""

import json
import urllib.request
import urllib.error
import sys


def load_config(config_path: str = "config.json") -> dict:
    """Load configuration from JSON file."""
    with open(config_path, "r") as f:
        return json.load(f)


def call_api(config: dict) -> dict:
    """Make API request based on config settings."""
    api_config = config.get("api", {})
    endpoint = api_config.get("endpoint", "")
    method = api_config.get("method", "GET").upper()
    headers = api_config.get("headers", {})
    timeout = api_config.get("timeout", 30)

    # Build request
    req = urllib.request.Request(endpoint, method=method)
    for key, value in headers.items():
        req.add_header(key, value)

    # Execute request
    try:
        with urllib.request.urlopen(req, timeout=timeout) as response:
            data = response.read()
            return {
                "status": "success",
                "status_code": response.status,
                "data": json.loads(data) if data else None
            }
    except urllib.error.HTTPError as e:
        return {
            "status": "error",
            "error": f"HTTP {e.code}: {e.reason}",
            "body": e.read().decode() if e.fp else None
        }
    except urllib.error.URLError as e:
        return {
            "status": "error",
            "error": f"URL Error: {e.reason}"
        }
    except Exception as e:
        return {
            "status": "error",
            "error": str(e)
        }


def main():
    config = load_config()
    result = call_api(config)
    print(json.dumps(result, indent=2))
    return 0 if result["status"] == "success" else 1


if __name__ == "__main__":
    sys.exit(main())

